parameters.content:
## Clara Tool - Agendar Consulta v2

Busca slots → match → cria agendamento + move pipeline.
Fallback: link de booking.

**Input:** { phone, data_preferida, horario_preferido, nome_contato }
**Output:** { sucesso, mensagem, data, hora } ou { link, slots[] }

parameters.jsCode:
// Validate input + unwrap $fromAI query fields
// n8n LangChain toolWorkflow puts $fromAI fields inside "query" object
// while static expressions stay at top level
const raw = $input.first().json;

// Merge query fields into top level
const query = raw.query || {};
const input = { ...raw };

// Unwrap query fields (AI-generated via $fromAI)
if (typeof query === 'object' && query !== null) {
  for (const [key, value] of Object.entries(query)) {
    if (key !== 'phone' && input[key] === undefined) {
      input[key] = value;
    }
  }
}
delete input.query;

// Validate phone
const phone = input.phone || '';
if (!phone || phone.trim() === '') {
  return [{ json: { resultado: 'Erro: telefone do lead não fornecido.', sucesso: false } }];
}

// Clean phone (remove non-digits, keep +)
input.phone = phone.replace(/[^\d+]/g, '');

return [{ json: input }];

// Process scheduling: find matching slot and prepare appointment
// Smart date matching: if AI sends past date, find preferred time in any available day
const input = $('Validar Input').first().json;

// Booking link fallback (GHL calendar widget)
const BOOKING_LINK = 'https://api.leadconnectorhq.com/widget/booking/afd4NA6ULMKfs8VDlaAs';

// Extract fields
const phone = input.phone || '';
const dataPref = input.data_preferida || '';
const horaPref = input.horario_preferido || '';
const nomeContato = input.nome_contato || '';

// Hardcoded IDs
const calendarId = 'afd4NA6ULMKfs8VDlaAs';
const locationId = 'LImTvhcHSBl9dFiTTZfD';

// Get contact from search
const contactData = $('GHL Buscar p/ Agendar').first().json;
let contactId = null;
if (contactData.contacts && contactData.contacts.length > 0) {
  contactId = contactData.contacts[0].id;
} else if (contactData.contact && contactData.contact.id) {
  contactId = contactData.contact.id;
}

// Parse available slots from GHL
const slotsData = $('GHL Slots Disponíveis').first().json;
const allSlots = [];
for (const [date, dateSlots] of Object.entries(slotsData)) {
  if (date === 'traceId' || date === '_metadata') continue;
  if (dateSlots && dateSlots.slots && Array.isArray(dateSlots.slots)) {
    dateSlots.slots.forEach(s => allSlots.push({ date, time: s }));
  } else if (Array.isArray(dateSlots)) {
    dateSlots.forEach(s => allSlots.push({ date, time: s }));
  }
}

// === FALLBACK: No contact found → send booking link ===
if (!contactId) {
  return [{ json: {
    action: 'fallback_link',
    message: 'Para agendar seu diagnóstico gratuito, é só clicar aqui: ' + BOOKING_LINK,
    link: BOOKING_LINK
  } }];
}

// === FALLBACK: No slots available → send booking link ===
if (allSlots.length === 0) {
  return [{ json: {
    action: 'fallback_link',
    message: 'No momento os horários estão atualizando. Você pode escolher o melhor horário direto aqui: ' + BOOKING_LINK,
    link: BOOKING_LINK
  } }];
}

// Check if preferred date is in the past or invalid
const today = new Date();
today.setHours(0, 0, 0, 0);
let dateIsValid = false;
if (dataPref) {
  const prefDate = new Date(dataPref + 'T00:00:00-03:00');
  dateIsValid = !isNaN(prefDate.getTime()) && prefDate >= today;
}

// Try to find matching slot
let selectedSlot = null;

if (horaPref) {
  const prefHour = parseInt(horaPref.split(':')[0]);
  const prefMin = parseInt(horaPref.split(':')[1] || '0');
  const prefMinutes = prefHour * 60 + prefMin;

  if (dateIsValid && dataPref) {
    // Valid date: try exact date match first
    const daySlots = allSlots.filter(s => s.date === dataPref);
    if (daySlots.length > 0) {
      let closest = daySlots[0];
      let minDiff = Infinity;
      for (const s of daySlots) {
        const slotTime = new Date(s.time);
        const slotHours = slotTime.getUTCHours() - 3; // BRT = UTC-3
        const slotMins = slotTime.getUTCMinutes();
        const diff = Math.abs((slotHours * 60 + slotMins) - prefMinutes);
        if (diff < minDiff) { minDiff = diff; closest = s; }
      }
      if (minDiff <= 60) selectedSlot = closest; // within 1 hour tolerance
    }
  }

  // If no exact date match (or date was past/invalid), find preferred time on ANY available day
  if (!selectedSlot) {
    let closest = null;
    let minDiff = Infinity;
    for (const s of allSlots) {
      const slotTime = new Date(s.time);
      const slotHours = slotTime.getUTCHours() - 3;
      const slotMins = slotTime.getUTCMinutes();
      const diff = Math.abs((slotHours * 60 + slotMins) - prefMinutes);
      if (diff < minDiff) { minDiff = diff; closest = s; }
    }
    if (closest && minDiff <= 60) selectedSlot = closest; // within 1 hour tolerance
  }
} else if (dateIsValid && dataPref) {
  // Only date preference, no time: pick first slot on that date
  const daySlots = allSlots.filter(s => s.date === dataPref);
  if (daySlots.length > 0) selectedSlot = daySlots[0];
}

// If no match within tolerance, offer available slots
if (!selectedSlot) {
  const topSlots = allSlots.slice(0, 8).map(s => {
    const d = new Date(s.time);
    return d.toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo', weekday: 'short', day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' });
  });
  return [{ json: {
    action: 'offer_slots',
    contactId,
    message: 'Temos esses horários disponíveis: ' + topSlots.join(' | ') + '. Qual fica melhor para você?',
    slots: topSlots,
    link: BOOKING_LINK
  } }];
}

// Found a slot - prepare appointment creation
const startTime = new Date(selectedSlot.time);
const endTime = new Date(startTime.getTime() + 30 * 60 * 1000); // 30 min

return [{ json: {
  action: 'create_appointment',
  contactId,
  calendarId,
  locationId,
  startTime: startTime.toISOString(),
  endTime: endTime.toISOString(),
  title: 'Diagnóstico - ' + (nomeContato || 'Lead'),
  appointmentStatus: 'confirmed',
  phone,
  nome: nomeContato
} }];

// Move or create opportunity at "Diagnóstico Agendado" stage
const opps = $('Buscar Opp Agendar').first().json.opportunities || [];
const procData = $('Processar Agendamento').first().json;
const contactId = procData.contactId;
const contactName = procData.nome || 'Lead';

const PIPELINE_ID = 'SdaTWIsioZOKhNrj2ecF';
const LOC_ID = 'LImTvhcHSBl9dFiTTZfD';
const STAGE_AGENDADO = '8725af03-5c92-40ae-9aa1-911016275dc4';

if (!contactId) {
  return [{ json: { method: 'GET', url: 'https://services.leadconnectorhq.com/calendars/', body: '' } }];
}

if (opps.length === 0) {
  // No opportunity → CREATE at Diagnóstico Agendado
  return [{ json: {
    method: 'POST',
    url: 'https://services.leadconnectorhq.com/opportunities/',
    body: JSON.stringify({
      pipelineId: PIPELINE_ID,
      locationId: LOC_ID,
      name: contactName + ' - Diagnóstico Agendado',
      pipelineStageId: STAGE_AGENDADO,
      contactId: contactId,
      status: 'open'
    })
  }}];
}

// Opportunity exists → MOVE to Diagnóstico Agendado
const opp = opps[0];
return [{ json: {
  method: 'PUT',
  url: 'https://services.leadconnectorhq.com/opportunities/' + opp.id,
  body: JSON.stringify({ pipelineStageId: STAGE_AGENDADO })
}}];

// Format appointment result for AI agent
// Two paths arrive here:
// 1. Criar: ...→ GHL Criar Agendamento → ... → Executar Pipeline → here
// 2. Fallback/Offer: Processar Agendamento → IF (false) → here
const input = $input.first().json;

// Try to read appointment from GHL Criar node
let appointmentId = null;
try {
  const appt = $('GHL Criar Agendamento').first().json;
  if (appt && appt.id) appointmentId = appt.id;
} catch (e) {}

// If appointment was created, read the time from Processar Agendamento
// (GHL response doesn't include startTime, but Processar has it)
if (appointmentId) {
  let startTime = null;
  try {
    const proc = $('Processar Agendamento').first().json;
    startTime = proc.startTime;
  } catch (e) {}

  if (startTime) {
    const start = new Date(startTime);
    const dataFormatada = start.toLocaleDateString('pt-BR', {
      timeZone: 'America/Sao_Paulo',
      weekday: 'long', day: '2-digit', month: '2-digit', year: 'numeric'
    });
    const horaFormatada = start.toLocaleTimeString('pt-BR', {
      timeZone: 'America/Sao_Paulo',
      hour: '2-digit', minute: '2-digit'
    });
    return [{ json: {
      sucesso: true,
      mensagem: 'Agendamento confirmado para ' + dataFormatada + ' às ' + horaFormatada + '! Você vai receber um convite no e-mail.',
      data: dataFormatada,
      hora: horaFormatada,
      appointment_id: appointmentId
    } }];
  }

  // Fallback: appointment created but no time info
  return [{ json: {
    sucesso: true,
    mensagem: 'Agendamento confirmado! Você vai receber um convite no e-mail com os detalhes.',
    appointment_id: appointmentId
  } }];
}

// Path 2: fallback_link
if (input.action === 'fallback_link') {
  return [{ json: {
    sucesso: true,
    mensagem: input.message,
    link: input.link
  } }];
}

// Path 2: offer_slots
if (input.action === 'offer_slots') {
  return [{ json: {
    sucesso: true,
    mensagem: input.message,
    slots: input.slots || [],
    link: input.link || ''
  } }];
}

// Fallback
const BOOKING_LINK = 'https://api.leadconnectorhq.com/widget/booking/afd4NA6ULMKfs8VDlaAs';
return [{ json: {
  sucesso: true,
  mensagem: 'Para agendar seu diagnóstico, acesse: ' + BOOKING_LINK,
  link: BOOKING_LINK
} }];

